import { NEW_POINT } from '../common/consts';
import { destinations, items, offersList } from '../mock/data';

export default class PointsModel {
  #destinations = [];
  #offers = [];
  #points = new Map();
  #newPoint = {};

  init() {
    this.#destinations = destinations;
    this.#offers = offersList;
    this.#points = new Map(items.map((item) => [item.id, item]));
    this.#newPoint = NEW_POINT;
  }

  get points() {
    return Array.from(this.#points.values());
  }

  get newPoint() {
    return this.#newPoint;
  }

  get offers() {
    return this.#offers;
  }

  get destinations() {
    return this.#destinations;
  }

  getPointById(id) {
    return this.#points.get(id);
  }

  getOffersByType(type) {
    return this.#offers.find((offer) => offer.type === type).offers;
  }

  getOffersById(type, targetIds) {
    const offersByType = this.getOffersByType(type);

    return offersByType.filter((offer) =>
      targetIds.find((id) => offer.id === id),
    );
  }

  getDestinationById(id) {
    return this.#destinations.find((dest) => dest.id === id);
  }

  updatePoint(data) {
    if (this.#points.has(data.id)) {
      this.#points.set(data.id, data);
    }
  }

  addPoint(data) {
    this.#points.set(data.id, data);
  }

  removePoint(id) {
    if (this.#points.has(id)) {
      this.#points.delete(id);
    }
  }
}
