import { FilterTypes, SortTypes, UpdateTypes } from '../common/consts';

export default class AppState {
  #isLoading = true;
  #points = new Map();
  #currentFilter = FilterTypes.EVERYTHING;
  #currentSort = SortTypes.DAY;
  #observers = [];

  set isLoading(isLoading) {
    this.#isLoading = isLoading;
    this.#notify(UpdateTypes.FullUpdate);
  }

  set points(points) {
    this.#points = new Map(points.map((point) => [point.id, point]));
    this.#notify(UpdateTypes.FullUpdate);
  }

  set currentFilter(filter) {
    this.#currentFilter = filter;
    this.#notify(UpdateTypes.FullUpdate);
  }

  set currentSort(sort) {
    this.#currentSort = sort;
    this.#notify(UpdateTypes.FullUpdate);
  }

  get isLoading() {
    return this.#isLoading;
  }

  get points() {
    return Array.from(this.#points.values());
  }

  get currentFilter() {
    return this.#currentFilter;
  }

  get currentSort() {
    return this.#currentSort;
  }

  get state() {
    return {
      isLoading: this.#isLoading,
      points: this.#points,
      currentFilter: this.#currentFilter,
      currentSort: this.#currentSort,
    };
  }

  subscribe(observer) {
    this.#observers.push(observer);
  }

  #notify(updateType, metadata = {}) {
    this.#observers.forEach((observer) =>
      observer(this.state, updateType, metadata),
    );
  }

  updatePoint(updatedPoint) {
    if (!this.#points.has(updatedPoint.id)) {
      return;
    }

    this.#points.set(updatedPoint.id, updatedPoint);
    this.#notify(UpdateTypes.SinglePointUpdate, { pointId: updatedPoint.id });
  }
}
